  ('heelevel3-c5fb3965-moex-00081', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-112-34cd00d7', 'sub-heelevel3-c5fb3965-02', NULL, 'essay', '甲男與乙女為合法夫妻，惟因甲在外與丙女同居，置乙女生活不顧，且偶
爾回家乙女即遭其毆打，乙女顧慮離婚對自己不利，乃訴請法院判決別
居，是否應予准許，以及法院是否得為別居之和解？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "74eccedf33c3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "304", "s": "1202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則、親屬與繼承編", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00082', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-112-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'essay', 'A市政府為管理市內攤販經營事業，制定攤販管理自治條例。其中規定，
攤販經營許可申請，如涉及私人土地，而不違反現行法令規定者，應檢具
所有權人同意書。市民丙申請經營攤販位於他人丁之所有土地上，於申請
時檢附所有權人丁之同意書，市政府發給許可證。於證件背面註記注意事
項：核准設攤地點涉及私人土地經所有權人提出異議時，應於一個月內提
供所有權人同意書，逾期未補正者，本府得註銷許可證之效力。丙開始經
營後，丁欲收回租地，向A市政府表示異議，市政府遂要求丙提出同意書，
逾期將廢止許可證。一個月期間過後，丙未能提出同意書，故市政府以B
函註銷許可證。請問：B函是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:37+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL)
